    public function parameterOptions(string $group='',bool $includeInactive=true):array{$out=[];if($group===''||$group!=='tpp'){$q=['select'=>'*','order'=>'group_code.asc,sort_order.asc,label.asc','limit'=>'2000'];if($group!=='')$q['group_code']='eq.'.$group;if(!$includeInactive)$q['active']='eq.true';$out=$this->rows($this->db->rest('GET','app_parameters',$q));}if($group===''||$group==='tpp')foreach($this->facilities($includeInactive) as $f)$out[]=['id'=>'facility--'.$f['id'],'group_code'=>'tpp','code'=>$f['id'],'label'=>$f['name'],'active'=>$f['active'],'system'=>true,'sort_order'=>$f['sort_order'],'created_at'=>$f['created_at']??null];return $out;}
