    public function setParameterActive(string $id,bool $active):void{if(str_starts_with($id,'facility--')){$this->db->rest('PATCH','facilities',['id'=>'eq.'.substr($id,10)],['active'=>$active]);}else$this->db->rest('PATCH','app_parameters',['id'=>'eq.'.$id],['active'=>$active,'updated_at'=>$this->now()]);}

    public function createDocument(array $file,string $actor):array{$name=basename((string)$file['name']);$tmp=(string)$file['tmp_name'];$size=(int)$file['size'];if($size<=0||$size>8*1024*1024||!is_uploaded_file($tmp)&&!is_file($tmp))throw new ApiException('Dokumen tidak valid atau melebihi 8 MB.',422);$content=(string)file_get_contents($tmp);$mime=(new \finfo(FILEINFO_MIME_TYPE))->buffer($content);$allowed=['application/pdf','image/jpeg','image/png','image/webp','image/gif'];if(!in_array($mime,$allowed,true))throw new ApiException('Format dokumen harus PDF atau gambar.',422);$sha=hash('sha256',$content);$path=gmdate('Y/m/d').'/'.bin2hex(random_bytes(16)).(['application/pdf'=>'.pdf','image/jpeg'=>'.jpg','image/png'=>'.png','image/webp'=>'.webp','image/gif'=>'.gif'][$mime]??'');$this->db->storage('POST',$this->config->storageBucket,$path,$mime,$content);try{return $this->first($this->db->rest('POST','uploaded_documents',['select'=>'id,file_name,mime_type,size_bytes,uploaded_by,storage_bucket,storage_path,sha256,created_at'],['file_name'=>$name,'mime_type'=>$mime,'size_bytes'=>$size,'sha256'=>$sha,'uploaded_by'=>$actor,'storage_bucket'=>$this->config->storageBucket,'storage_path'=>$path]));}catch(\Throwable $e){try{$this->db->storage('DELETE',$this->config->storageBucket,$path);}catch(\Throwable){}throw $e;}}
    public function getDocument(string $id):array{$row=$this->first($this->db->rest('GET','uploaded_documents',['select'=>'*','id'=>'eq.'.$id,'limit'=>'1']));$content=!empty($row['storage_path'])?$this->db->storage('GET',(string)$row['storage_bucket'],(string)$row['storage_path']):base64_decode((string)($row['content_base64']??''),true);if(!is_string($content)||strlen($content)!==(int)$row['size_bytes']||(!empty($row['sha256'])&&!hash_equals(strtolower((string)$row['sha256']),hash('sha256',$content))))throw new ApiException('Integritas dokumen tidak sesuai.',500);return [$row,$content];}
    public function documentAccess(string $id):array{$links=$this->rows($this->db->rest('GET','events',['select'=>'inventory_id,disposition_type,code','document_id'=>'eq.'.$id,'limit'=>'100']));if(!$links)throw new ApiException('Dokumen tidak ditemukan.',404);$ids=array_values(array_unique(array_filter(array_column($links,'inventory_id'))));$items=$ids?$this->rows($this->db->rest('GET','inventory_items',['select'=>'*','id'=>'in.('.implode(',',$ids).')'])):[];$by=[];foreach($items as $i)$by[$i['id']]=$i;$out=[];foreach($links as $l)if(isset($by[$l['inventory_id']]))$out[]=['inventory'=>$by[$l['inventory_id']],'disposition_type'=>$l['disposition_type']??'','event_code'=>$l['code']??''];return $out;}
