    private function date(mixed $v):?string{if(!is_string($v)||trim($v)==='')return null;$t=strtotime($v);return $t===false?null:date('Y-m-d',$t);}
    private function nullableDate(mixed $v):?string{$d=$this->date($v);return $d===null?null:$d;}
    private function bool(mixed $v):bool{return filter_var($v,FILTER_VALIDATE_BOOL)||in_array(strtolower((string)$v),['1','ya','yes','on'],true);}
    private function nullString(mixed $v):?string{$s=trim((string)$v);return $s===''?null:$s;}
    private function normalizeContainer(string $v,bool $formatted=true):string{$c=strtoupper(preg_replace('/[\s\-\.]+/','',trim($v)));if($c==='')return'';if(!preg_match('/^[A-Z]{4}[0-9]{7}$/',$c))throw new ApiException('Nomor kontainer harus 4 huruf dan 7 angka, contoh ABCD1234567.',422);return $formatted?substr($c,0,4).' '.substr($c,4,6).'-'.substr($c,10):$c;}
    private function slug(string $v):string{$v=strtolower(trim($v));$v=preg_replace('/[^a-z0-9]+/','_',$v);return trim((string)$v,'_');}
    private function normalizeApplies(string $group,array $values):string{$types=array_values(array_intersect(array_map('strtoupper',$values),Domain::TYPES));return in_array($group,['exit_type','transfer_type','load_type'],true)?implode(',',$types):'';}
